const source = $input.first().json.source;
const project = $input.first().json.project;
const response = ($input.first().json.response || '').substring(0, 6000);

const cleanResponse = response.replace(/"/g, '\\"').replace(/\n/g, '\\n');

const prompt = `Analisa esta resposta e extrai memorias uteis para sessoes futuras. Source: ${source} Project: ${project} Resposta: ${cleanResponse} Regras: So inclui informacao que seria util relembrar. Decisoes, erros, padroes, insights. Se nada relevante retorna []. Retorna APENAS um JSON array sem markdown sem backticks: [{"type": "Decision|Learning|Error|Insight|Pattern", "summary": "frase curta", "details": "contexto", "importance": 1-5, "tags": ["tag1"]}]`;

const body = {
  model: "claude-haiku-4-5-20251001",
  max_tokens: 1024,
  messages: [
    { role: "user", content: prompt }
  ]
};

return [{ json: { body: JSON.stringify(body) } }];

const content = $input.first().json.content[0].text;
const source = $('Execute Workflow Trigger').first().json.source;
const project = $('Execute Workflow Trigger').first().json.project;

let memories = [];
try {
  let cleaned = content.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  }
  memories = JSON.parse(cleaned);
} catch(e) {
  return [];
}

if (!Array.isArray(memories) || memories.length === 0) {
  return [];
}

return memories.map(m => ({
  json: {
    source: source,
    project: project,
    type: m.type || 'Insight',
    summary: m.summary || '',
    details: m.details || '',
    importance: m.importance || 3,
    tags: Array.isArray(m.tags) ? m.tags : [m.tags || '']
  }
}));

const similarResults = $input.first().json;
const prev = $('Merge Embedding').item.json;

const hasSimilar = Array.isArray(similarResults) && similarResults.length > 0 && similarResults[0]?.id;

if (hasSimilar) {
  return [{ json: { action: 'update', existingId: similarResults[0].id, similarity: similarResults[0].similarity, ...prev } }];
} else {
  return [{ json: { action: 'insert', ...prev } }];
}

const mem = $('Parse Memories JSON').item.json;
const embedding = $json.data[0].embedding;
return [{ json: { ...mem, embedding } }];

const item = $input.first().json;
const body = JSON.stringify({
  query_embedding: item.embedding,
  similarity_threshold: 0.85,
  filter_project: item.project
});
return [{ json: { ...item, similarBody: body } }];

// Circuit Breaker — suprime escritas duplicadas (cascata de erro)
// Chave: source + project + hash(response). Janela 15min. Limite N=2 (1ª passa, duplicados suprimem).
const item = $input.first().json;
const source = item.source || 'unknown';
const project = item.project || 'unknown';
const response = item.response || '';

// hash simples e estável do conteúdo (primeiros 200 chars bastam p/ identificar duplicado)
function hashStr(s) {
  let h = 0;
  const sub = s.substring(0, 200);
  for (let i = 0; i < sub.length; i++) {
    h = ((h << 5) - h + sub.charCodeAt(i)) | 0;
  }
  return h.toString(36);
}

const key = `${source}|${project}|${hashStr(response)}`;
const now = Date.now();
const WINDOW_MS = 15 * 60 * 1000; // 15 min
const LIMIT = 2;                   // 1ª passa; a partir da 2ª na janela, suprime

const store = $getWorkflowStaticData('global');
if (!store.cb) store.cb = {};

// limpar entradas expiradas (housekeeping para não crescer infinito)
for (const k of Object.keys(store.cb)) {
  store.cb[k] = store.cb[k].filter(ts => now - ts < WINDOW_MS);
  if (store.cb[k].length === 0) delete store.cb[k];
}

const hits = store.cb[key] || [];
const recentHits = hits.filter(ts => now - ts < WINDOW_MS);

if (recentHits.length >= LIMIT) {
  // SUPRIMIR — duplicado dentro da janela. Termina sem gravar.
  return [];   // array vazio = workflow termina, nada a jusante corre
}

// passa: regista o hit e deixa seguir para Prepare Haiku Body
recentHits.push(now);
store.cb[key] = recentHits;
return [{ json: item }];   // propaga o input intacto
